from Bio.PDB import PDBParser, HSExposureCB
from Bio.PDB.DSSP import DSSP
# Use PLIP for the most detailed H-bond analysis
# or use gemmi for fast contact search
import gemmi
st = gemmi.read_structure('4dkl.pdb')
ns = gemmi.NeighborSearch(st[0], st.cell, 4.0)
ns.populate(include_h=False)
# Find contacts between ligand and protein
hbond_candidates = []
for chain in st[0]:
    for res in chain:
        if res.name == 'LIG':
            for atom in res:
                if atom.element.name in ('N', 'O', 'S'):
                    for nb in ns.find_atoms(atom.pos, '\0', radius=3.5):
                        cra = nb.to_cra(st[0])
                        if cra.atom.element.name in ('N', 'O') and cra.residue.name != res.name:
                            hbond_candidates.append(
                                (atom.name, cra.chain.name, cra.residue.name,
                                 str(cra.residue.seqid), cra.atom.name, round(nb.dist(), 2))
                            )
for h in hbond_candidates:
    print(f'Ligand {h[0]} — {h[2]}{h[3]} {h[4]} ({h[5]} Å)')
```

This finds all N/O contacts within 3.5 Å between LIG and protein — strong H-bond candidates. For full H-bond analysis including angles, use PLIP: `plip -f 4dkl.pdb -x -o plip_output/`

