import gemmi
st = gemmi.read_structure('4DKL.pdb')
ns = gemmi.NeighborSearch(st[0], st.cell, 5.0)
ns.populate()
# Find contacts from ligand atoms
for chain in st[0]:
    for res in chain:
        if res.het_flag == 'H' and res.name != 'HOH':
            for atom in res:
                for nb in ns.find_atoms(atom.pos, '\0', radius=4.0):
                    mark = nb.to_cra(st[0])
                    if mark.residue.het_flag != 'H':
                        print(f'{atom.name}-{mark.chain.name}/{mark.residue.name}{mark.residue.seqid}/{mark.atom.name}: {nb.dist():.2f} A')
```

